            best_res = 10**9
            for rx, ry in resources:
                d = abs(x - rx) + abs(y - ry)
                if d < best_res:
                    best_res = d
            res_term = -best_res * 3
        else:
            cx, cy = (w - 1) / 2.0, (h - 1) / 2.0
            res_term = -((x - cx) ** 2 + (y - cy) ** 2) ** 0.5

        opp_d = abs(x - ox) + abs(y - oy)
        opp_term = opp_d * 1.5
        return res_term + opp_term

    best = None
    best_sc = -10**18
    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not inb(nx, ny):
            continue
        sc = score_for(nx, ny)
        if sc > best_sc:
            best_sc = sc
            best = [dx, dy]
        elif sc == best_sc and best is not None:
            if (dx, dy) < (best[0], best[1]):
                best = [dx, dy]

    if best is None:
        for dx, dy in dirs:
            nx, ny = sx + dx, sy + dy
            if inb(nx, ny):
                return [dx, dy]
        return [0, 0]
    return best
